-- DMT_V_RCV_TRANSACTIONS_DETAIL
CREATE OR REPLACE FORCE EDITIONABLE VIEW "DMT_V_RCV_TRANSACTIONS_DETAIL" ("RUN_STATUS", "ERROR_TEXT", "RECONCILIATION_STATUS", "DOCUMENT_NUM", "PROCESSING_STATUS_CODE", "PROCESSING_MODE_CODE", "TRANSACTION_STATUS_CODE", "INTERFACE_LINE_NUM", "TRANSACTION_TYPE", "AUTO_TRANSACT_CODE", "TRANSACTION_DATE", "SOURCE_DOCUMENT_CODE", "RECEIPT_SOURCE_CODE", "HEADER_INTERFACE_NUM", "PARENT_TRANSACTION_ID", "PARENT_INTF_LINE_NUM", "TO_ORGANIZATION_CODE", "ITEM_NUM", "ITEM_DESCRIPTION", "ITEM_REVISION", "DOCUMENT_LINE_NUM", "DOCUMENT_SHIPMENT_LINE_NUM", "DOCUMENT_DISTRIBUTION_NUM", "BUSINESS_UNIT", "SHIPMENT_NUM", "EXPECTED_RECEIPT_DATE", "SUBINVENTORY", "LOCATOR", "QUANTITY", "UNIT_OF_MEASURE", "PRIMARY_QUANTITY", "PRIMARY_UNIT_OF_MEASURE", "SECONDARY_QUANTITY", "SECONDARY_UNIT_OF_MEASURE", "VENDOR_NAME", "VENDOR_NUM", "VENDOR_SITE_CODE", "CUSTOMER_PARTY_NAME", "CUSTOMER_PARTY_NUMBER", "CUSTOMER_ACCOUNT_NUMBER", "SHIP_TO_LOCATION_CODE", "LOCATION_CODE", "REASON_NAME", "DELIVER_TO_PERSON_NAME", "DELIVER_TO_LOCATION_CODE", "RECEIPT_EXCEPTION_FLAG", "ROUTING_HEADER_ID", "DESTINATION_TYPE_CODE", "INTERFACE_SOURCE_CODE", "INTERFACE_SOURCE_LINE_ID", "AMOUNT", "CURRENCY_CODE", "CURRENCY_CONVERSION_TYPE", "CURRENCY_CONVERSION_RATE", "CURRENCY_CONVERSION_DATE", "INSPECTION_STATUS_CODE", "INSPECTION_QUALITY_CODE", "FROM_ORGANIZATION_CODE", "FROM_SUBINVENTORY", "FROM_LOCATOR", "FREIGHT_CARRIER_NAME", "BILL_OF_LADING", "PACKING_SLIP", "SHIPPED_DATE", "NUM_OF_CONTAINERS", "WAYBILL_AIRBILL_NUM", "RMA_REFERENCE", "COMMENTS", "TRUCK_NUM", "CONTAINER_NUM", "SUBSTITUTE_ITEM_NUM", "NOTICE_UNIT_PRICE", "ITEM_CATEGORY", "INTRANSIT_OWNING_ORG_CODE", "ROUTING_CODE", "VALIDATION_FLAG", "BARCODE_LABEL", "COUNTRY_OF_ORIGIN_CODE", "CREATE_DEBIT_MEMO_FLAG", "LICENSE_PLATE_NUMBER", "TRANSFER_LICENSE_PLATE_NUMBER", "LPN_GROUP_NUM", "ASN_LINE_NUM", "EMPLOYEE_NAME", "SOURCE_TRANSACTION_NUM", "PARENT_SOURCE_TRANSACTION_NUM", "PARENT_INTERFACE_TXN_ID", "MATCHING_BASIS", "RA_OUTSOURCER_PARTY_NAME", "RA_DOCUMENT_NUMBER", "RA_DOCUMENT_LINE_NUMBER", "RA_NOTE_TO_RECEIVER", "RA_VENDOR_SITE_NAME", "ATTRIBUTE_CATEGORY", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "ATTRIBUTE11", "ATTRIBUTE12", "ATTRIBUTE13", "ATTRIBUTE14", "ATTRIBUTE15", "ATTRIBUTE16", "ATTRIBUTE17", "ATTRIBUTE18", "ATTRIBUTE19", "ATTRIBUTE20", "ATTRIBUTE_NUMBER1", "ATTRIBUTE_NUMBER2", "ATTRIBUTE_NUMBER3", "ATTRIBUTE_NUMBER4", "ATTRIBUTE_NUMBER5", "ATTRIBUTE_NUMBER6", "ATTRIBUTE_NUMBER7", "ATTRIBUTE_NUMBER8", "ATTRIBUTE_NUMBER9", "ATTRIBUTE_NUMBER10", "ATTRIBUTE_DATE1", "ATTRIBUTE_DATE2", "ATTRIBUTE_DATE3", "ATTRIBUTE_DATE4", "ATTRIBUTE_DATE5", "ATTRIBUTE_TIMESTAMP1", "ATTRIBUTE_TIMESTAMP2", "ATTRIBUTE_TIMESTAMP3", "ATTRIBUTE_TIMESTAMP4", "ATTRIBUTE_TIMESTAMP5", "CONSIGNED_FLAG", "SOLDTO_LEGAL_ENTITY", "CONSUMED_QUANTITY", "DEFAULT_TAXATION_COUNTRY", "TRX_BUSINESS_CATEGORY", "DOCUMENT_FISCAL_CLASSIFICATION", "USER_DEFINED_FISC_CLASS", "PRODUCT_FISC_CLASS_NAME", "INTENDED_USE", "PRODUCT_CATEGORY", "TAX_CLASSIFICATION_CODE", "PRODUCT_TYPE", "FIRST_PTY_NUMBER", "THIRD_PTY_NUMBER", "TAX_INVOICE_NUMBER", "TAX_INVOICE_DATE", "FINAL_DISCHARGE_LOC_CODE", "ASSESSABLE_VALUE", "PHYSICAL_RETURN_REQD", "EXTERNAL_SYSTEM_PACKING_UNIT", "EWAY_BILL_NUMBER", "EWAY_BILL_DATE", "RECALL_NOTICE_NUMBER", "RECALL_LINE_NUMBER", "EXTERNAL_SYS_TXN_REFERENCE", "DEFAULT_LOTSER_FROM_ASN", "EMPLOYEE_ID", "DEFAULT_LOTSER_FROM_TO", "FOB_LOOKUP_CODE", "RETURN_FOR_CREDIT_FLAG", "SOURCE_ID", "STG_SEQUENCE_ID", "RUN_ID", "INTEGRATION_ID", "PREFIX", "SCENARIO_ID", "STAGE_DATE", "LAST_UPDATED_DATE")  AS 
  SELECT
    NVL(tfm.TFM_STATUS, stg.STG_STATUS)                             AS RUN_STATUS,
    tfm.ERROR_TEXT                                           AS ERROR_TEXT,
    CASE
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'LOADED' THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NOT NULL THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NULL THEN 'UNRECONCILED'
        ELSE 'IN_PROGRESS'
    END                                                      AS RECONCILIATION_STATUS,
    stg.DOCUMENT_NUM                                        AS DOCUMENT_NUM,
    stg.PROCESSING_STATUS_CODE,
    stg.PROCESSING_MODE_CODE,
    stg.TRANSACTION_STATUS_CODE,
    stg.INTERFACE_LINE_NUM,
    stg.TRANSACTION_TYPE,
    stg.AUTO_TRANSACT_CODE,
    stg.TRANSACTION_DATE,
    stg.SOURCE_DOCUMENT_CODE,
    stg.RECEIPT_SOURCE_CODE,
    stg.HEADER_INTERFACE_NUM,
    stg.PARENT_TRANSACTION_ID,
    stg.PARENT_INTF_LINE_NUM,
    stg.TO_ORGANIZATION_CODE,
    stg.ITEM_NUM,
    stg.ITEM_DESCRIPTION,
    stg.ITEM_REVISION,
    stg.DOCUMENT_LINE_NUM,
    stg.DOCUMENT_SHIPMENT_LINE_NUM,
    stg.DOCUMENT_DISTRIBUTION_NUM,
    stg.BUSINESS_UNIT,
    stg.SHIPMENT_NUM,
    stg.EXPECTED_RECEIPT_DATE,
    stg.SUBINVENTORY,
    stg.LOCATOR,
    stg.QUANTITY,
    stg.UNIT_OF_MEASURE,
    stg.PRIMARY_QUANTITY,
    stg.PRIMARY_UNIT_OF_MEASURE,
    stg.SECONDARY_QUANTITY,
    stg.SECONDARY_UNIT_OF_MEASURE,
    stg.VENDOR_NAME,
    stg.VENDOR_NUM,
    stg.VENDOR_SITE_CODE,
    stg.CUSTOMER_PARTY_NAME,
    stg.CUSTOMER_PARTY_NUMBER,
    stg.CUSTOMER_ACCOUNT_NUMBER,
    stg.SHIP_TO_LOCATION_CODE,
    stg.LOCATION_CODE,
    stg.REASON_NAME,
    stg.DELIVER_TO_PERSON_NAME,
    stg.DELIVER_TO_LOCATION_CODE,
    stg.RECEIPT_EXCEPTION_FLAG,
    stg.ROUTING_HEADER_ID,
    stg.DESTINATION_TYPE_CODE,
    stg.INTERFACE_SOURCE_CODE,
    stg.INTERFACE_SOURCE_LINE_ID,
    stg.AMOUNT,
    stg.CURRENCY_CODE,
    stg.CURRENCY_CONVERSION_TYPE,
    stg.CURRENCY_CONVERSION_RATE,
    stg.CURRENCY_CONVERSION_DATE,
    stg.INSPECTION_STATUS_CODE,
    stg.INSPECTION_QUALITY_CODE,
    stg.FROM_ORGANIZATION_CODE,
    stg.FROM_SUBINVENTORY,
    stg.FROM_LOCATOR,
    stg.FREIGHT_CARRIER_NAME,
    stg.BILL_OF_LADING,
    stg.PACKING_SLIP,
    stg.SHIPPED_DATE,
    stg.NUM_OF_CONTAINERS,
    stg.WAYBILL_AIRBILL_NUM,
    stg.RMA_REFERENCE,
    stg.COMMENTS,
    stg.TRUCK_NUM,
    stg.CONTAINER_NUM,
    stg.SUBSTITUTE_ITEM_NUM,
    stg.NOTICE_UNIT_PRICE,
    stg.ITEM_CATEGORY,
    stg.INTRANSIT_OWNING_ORG_CODE,
    stg.ROUTING_CODE,
    stg.VALIDATION_FLAG,
    stg.BARCODE_LABEL,
    stg.COUNTRY_OF_ORIGIN_CODE,
    stg.CREATE_DEBIT_MEMO_FLAG,
    stg.LICENSE_PLATE_NUMBER,
    stg.TRANSFER_LICENSE_PLATE_NUMBER,
    stg.LPN_GROUP_NUM,
    stg.ASN_LINE_NUM,
    stg.EMPLOYEE_NAME,
    stg.SOURCE_TRANSACTION_NUM,
    stg.PARENT_SOURCE_TRANSACTION_NUM,
    stg.PARENT_INTERFACE_TXN_ID,
    stg.MATCHING_BASIS,
    stg.RA_OUTSOURCER_PARTY_NAME,
    stg.RA_DOCUMENT_NUMBER,
    stg.RA_DOCUMENT_LINE_NUMBER,
    stg.RA_NOTE_TO_RECEIVER,
    stg.RA_VENDOR_SITE_NAME,
    stg.ATTRIBUTE_CATEGORY,
    stg.ATTRIBUTE1,
    stg.ATTRIBUTE2,
    stg.ATTRIBUTE3,
    stg.ATTRIBUTE4,
    stg.ATTRIBUTE5,
    stg.ATTRIBUTE6,
    stg.ATTRIBUTE7,
    stg.ATTRIBUTE8,
    stg.ATTRIBUTE9,
    stg.ATTRIBUTE10,
    stg.ATTRIBUTE11,
    stg.ATTRIBUTE12,
    stg.ATTRIBUTE13,
    stg.ATTRIBUTE14,
    stg.ATTRIBUTE15,
    stg.ATTRIBUTE16,
    stg.ATTRIBUTE17,
    stg.ATTRIBUTE18,
    stg.ATTRIBUTE19,
    stg.ATTRIBUTE20,
    stg.ATTRIBUTE_NUMBER1,
    stg.ATTRIBUTE_NUMBER2,
    stg.ATTRIBUTE_NUMBER3,
    stg.ATTRIBUTE_NUMBER4,
    stg.ATTRIBUTE_NUMBER5,
    stg.ATTRIBUTE_NUMBER6,
    stg.ATTRIBUTE_NUMBER7,
    stg.ATTRIBUTE_NUMBER8,
    stg.ATTRIBUTE_NUMBER9,
    stg.ATTRIBUTE_NUMBER10,
    stg.ATTRIBUTE_DATE1,
    stg.ATTRIBUTE_DATE2,
    stg.ATTRIBUTE_DATE3,
    stg.ATTRIBUTE_DATE4,
    stg.ATTRIBUTE_DATE5,
    stg.ATTRIBUTE_TIMESTAMP1,
    stg.ATTRIBUTE_TIMESTAMP2,
    stg.ATTRIBUTE_TIMESTAMP3,
    stg.ATTRIBUTE_TIMESTAMP4,
    stg.ATTRIBUTE_TIMESTAMP5,
    stg.CONSIGNED_FLAG,
    stg.SOLDTO_LEGAL_ENTITY,
    stg.CONSUMED_QUANTITY,
    stg.DEFAULT_TAXATION_COUNTRY,
    stg.TRX_BUSINESS_CATEGORY,
    stg.DOCUMENT_FISCAL_CLASSIFICATION,
    stg.USER_DEFINED_FISC_CLASS,
    stg.PRODUCT_FISC_CLASS_NAME,
    stg.INTENDED_USE,
    stg.PRODUCT_CATEGORY,
    stg.TAX_CLASSIFICATION_CODE,
    stg.PRODUCT_TYPE,
    stg.FIRST_PTY_NUMBER,
    stg.THIRD_PTY_NUMBER,
    stg.TAX_INVOICE_NUMBER,
    stg.TAX_INVOICE_DATE,
    stg.FINAL_DISCHARGE_LOC_CODE,
    stg.ASSESSABLE_VALUE,
    stg.PHYSICAL_RETURN_REQD,
    stg.EXTERNAL_SYSTEM_PACKING_UNIT,
    stg.EWAY_BILL_NUMBER,
    stg.EWAY_BILL_DATE,
    stg.RECALL_NOTICE_NUMBER,
    stg.RECALL_LINE_NUMBER,
    stg.EXTERNAL_SYS_TXN_REFERENCE,
    stg.DEFAULT_LOTSER_FROM_ASN,
    stg.EMPLOYEE_ID,
    stg.DEFAULT_LOTSER_FROM_TO,
    stg.FOB_LOOKUP_CODE,
    stg.RETURN_FOR_CREDIT_FLAG,
    stg.SOURCE_ID,
    stg.STG_SEQUENCE_ID,
    tfm.RUN_ID,
    tfm.RUN_ID                                              AS INTEGRATION_ID,
    cm.PREFIX,
    stg.SCENARIO_ID,
    stg.STAGE_DATE,
    NVL(tfm.LAST_UPDATED_DATE, stg.LAST_UPDATED_DATE)      AS LAST_UPDATED_DATE
FROM DMT_OWNER.DMT_RCV_TRANSACTIONS_STG_TBL stg
LEFT JOIN (
    SELECT t.*,
           ROW_NUMBER() OVER (PARTITION BY t.STG_SEQUENCE_ID
                              ORDER BY t.TFM_SEQUENCE_ID DESC) AS rn
    FROM   DMT_OWNER.DMT_RCV_TRANSACTIONS_TFM_TBL t
) tfm ON tfm.STG_SEQUENCE_ID = stg.STG_SEQUENCE_ID AND tfm.rn = 1
LEFT JOIN DMT_OWNER.DMT_PIPELINE_RUN_TBL cm
    ON cm.RUN_ID = tfm.RUN_ID;
